#include <SPI.h>
#include <SD.h>

extern int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float* intg,float* lastE);

const float SP=65.0f,KP=2.0f,KI=0.1f,KD=0.5f,GRAD_MAX=15.0f,TEMP_MAX=80.0f;
const int HEAT_PIN=9,SD_CS=10,N=4;
const int SPINS[4]={A0,A1,A2,A3};
float intg=0,lastE=0,maturity=0;
bool sd_ok=false;

// === PT100 Array ===
void sensors_init(){for(int i=0;i<N;i++)pinMode(SPINS[i],INPUT);}
float sensors_avg(){float s=0;for(int i=0;i<N;i++)s+=analogRead(SPINS[i])*0.4883f;return s/N;}
float sensors_gradient(){int mx=0,mn=1023;for(int i=0;i<N;i++){int v=analogRead(SPINS[i]);if(v>mx)mx=v;if(v<mn)mn=v;}return(mx-mn)*0.4883f;}

// === Heating Blanket ===
void blanket_init(){pinMode(HEAT_PIN,OUTPUT);analogWrite(HEAT_PIN,0);}
void blanket_set(int p){analogWrite(HEAT_PIN,constrain(p,0,255));}

// === SD Logger ===
void logger_init(){sd_ok=SD.begin(SD_CS);if(sd_ok){File f=SD.open("cure.csv",FILE_WRITE);if(f){f.println("epoch,t0,t1,t2,t3,avg,grad,pwm,maturity,fault");f.close();}}}
void logger_write(unsigned long ep,float avg,float grad,int pwm,float mat,bool fa){
  if(!sd_ok)return;
  File f=SD.open("cure.csv",FILE_WRITE);
  if(f){f.print(ep);f.print(',');f.print(avg,2);f.print(',');f.print(grad,2);f.print(',');f.print(pwm);f.print(',');f.print(mat,1);f.print(',');f.println(fa?1:0);f.close();}}

// === Maturity ===
void maturity_update(float t,float dt_s){if(t>-10.0f)maturity+=(t+10.0f)*dt_s/3600.0f;}

// === Fault Handler ===
bool fault_check(float t,float g){if(t>TEMP_MAX||t<-5.0f){blanket_set(0);Serial.println("FAULT:TEMP");return true;}if(g>GRAD_MAX){blanket_set(0);Serial.println("FAULT:GRAD");return true;}return false;}

void setup(){
  Serial.begin(115200);
  sensors_init();blanket_init();logger_init();
  Serial.println("Concrete Cure Controller Ready");
}

unsigned long lastMs=0;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<1.0f)return;
  lastMs=now;
  float pv=sensors_avg(),grad=sensors_gradient();
  bool fault=fault_check(pv,grad);
  int pwm=0;
  if(!fault)pwm=pid_heater_control(SP,pv,dt,KP,KI,KD,&intg,&lastE);
  blanket_set(pwm);
  maturity_update(pv,dt);
  logger_write(now/1000,pv,grad,pwm,maturity,fault);
  Serial.print("T=");Serial.print(pv,1);Serial.print(" M=");Serial.print(maturity,0);Serial.print(" G=");Serial.println(grad,1);
}
